import { BrowserRouter, Navigate, Route, Routes } from "react-router-dom";
import { ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import Navbar from "./components/Navbar";
import QuoteBar from "./components/QuoteBar";
import VerbTable from "./components/verb/VerbTable";
import WordList from "./components/word/WordList";
import { AuthProvider, useAuth } from "./context/AuthContext";
import { ProgressProvider } from "./context/ProgressContext";
import AuthPage from "./pages/AuthPage";
import DashboardPage from "./pages/DashboardPage";
import HomePage from "./pages/HomePage";
import LessonPage from "./pages/LessonPage";

function Layout({ children }) {
  return (
    <div className="min-h-screen">
      <QuoteBar />
      <Navbar />
      <main>{children}</main>
    </div>
  );
}

function PrivateRoute({ children }) {
  const { user, loading } = useAuth();
  if (loading)
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="text-5xl animate-bounce mb-4">🗣️</div>
          <p className="text-slate-500 font-bold">Loading SpeakUp...</p>
        </div>
      </div>
    );
  return user ? children : <Navigate to="/auth" />;
}

function AppRoutes() {
  const { user, loading } = useAuth();
  if (loading) return null;

  return (
    <Routes>
      <Route path="/auth" element={user ? <Navigate to="/" /> : <AuthPage />} />
      <Route
        path="/"
        element={
          <PrivateRoute>
            <Layout>
              <HomePage />
            </Layout>
          </PrivateRoute>
        }
      />
      <Route
        path="/lesson/:levelId/:day"
        element={
          <PrivateRoute>
            <Layout>
              <LessonPage />
            </Layout>
          </PrivateRoute>
        }
      />
      <Route
        path="/dashboard"
        element={
          <PrivateRoute>
            <Layout>
              <DashboardPage />
            </Layout>
          </PrivateRoute>
        }
      />
      <Route
        path="/verbs"
        element={
          <PrivateRoute>
            <Layout>
              <VerbTable />
            </Layout>
          </PrivateRoute>
        }
      />
      <Route
        path="/words"
        element={
          <PrivateRoute>
            <Layout>
              <WordList />
            </Layout>
          </PrivateRoute>
        }
      />

      <Route path="*" element={<Navigate to="/" />} />
    </Routes>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <ProgressProvider>
          <AppRoutes />
          <ToastContainer
            position="bottom-right"
            autoClose={2500}
            hideProgressBar={false}
            newestOnTop
            closeOnClick
            pauseOnHover
            toastClassName="font-nunito font-bold text-sm"
          />
        </ProgressProvider>
      </AuthProvider>
    </BrowserRouter>
  );
}
